最簡單嘅做法<br />
<pre><code data-type="js">function chooseStrikePrice() {
  if (predict.probability &gt;= 0.8 &amp;&amp; predict.achieveDay &lt; 2) {
    return &quot;OTM within 1.5 months&quot;;
  } else if (predict.probability &gt;= 0.6 &amp;&amp; predict.achieveDay &lt; 10) {
    return &quot;ITM within 3 months&quot;;
  } else {
    return null;
  }
}</code></pre>

